-- ============================================================
-- 二手物品交易系统 - 数据库初始化脚本
-- 数据库: MySQL 5.7+
-- ============================================================

-- 建库
CREATE DATABASE IF NOT EXISTS `secondhand_trade`
    DEFAULT CHARACTER SET utf8mb4
    DEFAULT COLLATE utf8mb4_unicode_ci;

USE `secondhand_trade`;

-- 强制客户端使用 utf8mb4（修复 Docker MySQL 5.7 默认 latin1 导致的中文乱码）
SET NAMES utf8mb4;

-- ============================================================
-- user 表（3 张物理分片表，分片键: user_id % 3）
-- ============================================================
CREATE TABLE IF NOT EXISTS `user_0` (
    `user_id`    BIGINT       NOT NULL AUTO_INCREMENT COMMENT '用户ID',
    `username`   VARCHAR(50)  NOT NULL COMMENT '用户名',
    `password`   VARCHAR(255) NOT NULL COMMENT '密码(SHA256)',
    `role`       TINYINT      NOT NULL DEFAULT 0 COMMENT '0:普通用户 1:管理员',
    `nickname`   VARCHAR(50)  DEFAULT NULL COMMENT '昵称',
    `phone`      VARCHAR(20)  DEFAULT NULL COMMENT '手机号',
    `is_muted`   TINYINT      NOT NULL DEFAULT 0 COMMENT '0:正常 1:禁言',
    `created_at` DATETIME     NOT NULL COMMENT '创建时间',
    `updated_at` DATETIME     NOT NULL COMMENT '更新时间',
    PRIMARY KEY (`user_id`),
    UNIQUE KEY `uk_username` (`username`),
    KEY `idx_role` (`role`) COMMENT '按角色查询'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='用户表_0';

CREATE TABLE IF NOT EXISTS `user_1` LIKE `user_0`;
CREATE TABLE IF NOT EXISTS `user_2` LIKE `user_0`;

-- ============================================================
-- product 表（3 张物理分片表，分片键: user_id % 3）
-- 商品 ID 格式: YYYYMMDD + 6位序号，不依赖 AUTO_INCREMENT
-- ============================================================
CREATE TABLE IF NOT EXISTS `product_0` (
    `product_id`   BIGINT        NOT NULL COMMENT '商品ID(YYYYMMDD+6位序号)',
    `name`         VARCHAR(100)  NOT NULL COMMENT '商品名称',
    `price`        DECIMAL(10,2) NOT NULL COMMENT '价格',
    `description`  TEXT          DEFAULT NULL COMMENT '商品介绍',
    `pickup_point` VARCHAR(200)  DEFAULT NULL COMMENT '自提点',
    `user_id`      BIGINT        NOT NULL COMMENT '商家用户ID',
    `seller_name`  VARCHAR(50)   DEFAULT NULL COMMENT '卖家昵称',
    `status`       TINYINT       NOT NULL DEFAULT 1 COMMENT '1:上架 0:下架',
    `created_at`   DATETIME      NOT NULL COMMENT '创建时间',
    `updated_at`   DATETIME      NOT NULL COMMENT '更新时间',
    PRIMARY KEY (`product_id`),
    KEY `idx_user` (`user_id`),
    KEY `idx_name` (`name`),
    KEY `idx_status_created` (`status`, `created_at` DESC) COMMENT '上架商品按时间排序',
    KEY `idx_user_status` (`user_id`, `status`) COMMENT '用户商品查询'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='商品表_0';

CREATE TABLE IF NOT EXISTS `product_1` LIKE `product_0`;
CREATE TABLE IF NOT EXISTS `product_2` LIKE `product_0`;

-- ============================================================
-- chat_message 表（3 张物理分片表，分片键: from_user_id % 3）
-- ============================================================
CREATE TABLE IF NOT EXISTS `chat_message_0` (
    `msg_id`       BIGINT   NOT NULL AUTO_INCREMENT COMMENT '消息ID',
    `from_user_id` BIGINT   NOT NULL COMMENT '发送者ID',
    `to_user_id`   BIGINT   NOT NULL COMMENT '接收者ID',
    `product_id`   BIGINT   DEFAULT NULL COMMENT '关联商品ID',
    `content`      TEXT     NOT NULL COMMENT '消息内容',
    `has_read`     TINYINT  NOT NULL DEFAULT 0 COMMENT '0:未读 1:已读',
    `created_at`   DATETIME NOT NULL COMMENT '发送时间',
    PRIMARY KEY (`msg_id`),
    KEY `idx_from_to` (`from_user_id`, `to_user_id`),
    KEY `idx_users_time` (`from_user_id`, `to_user_id`, `created_at`),
    KEY `idx_product` (`product_id`) COMMENT '按商品查聊天',
    KEY `idx_users_msg` (`from_user_id`, `to_user_id`, `msg_id`) COMMENT '聊天轮询加速'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='聊天消息表_0';

CREATE TABLE IF NOT EXISTS `chat_message_1` LIKE `chat_message_0`;
CREATE TABLE IF NOT EXISTS `chat_message_2` LIKE `chat_message_0`;

