-- ============================================================
-- 4. 验证数据
-- ============================================================
SELECT '====== 数据初始化完成 ======' AS '';
SELECT CONCAT('用户: ', (SELECT COUNT(*) FROM (SELECT 1 FROM user_0 UNION ALL SELECT 1 FROM user_1 UNION ALL SELECT 1 FROM user_2) t)) AS '统计';
SELECT CONCAT('商品: ', (SELECT COUNT(*) FROM (SELECT 1 FROM product_0 UNION ALL SELECT 1 FROM product_1 UNION ALL SELECT 1 FROM product_2) t)) AS '统计';
SELECT CONCAT('消息: ',  (SELECT COUNT(*) FROM (SELECT 1 FROM chat_message_0 UNION ALL SELECT 1 FROM chat_message_1 UNION ALL SELECT 1 FROM chat_message_2) t)) AS '统计';

SELECT '====== 各用户商品数 ======' AS '';
SELECT user_id, seller_name, COUNT(*) AS cnt FROM (
    SELECT user_id, seller_name FROM product_0
    UNION ALL SELECT user_id, seller_name FROM product_1
    UNION ALL SELECT user_id, seller_name FROM product_2
) t GROUP BY user_id, seller_name ORDER BY user_id;

-- ============================================================
-- 使用说明:
-- 1. 执行本脚本即可创建数据库、表并导入完整测试数据
-- 2. 确保 ShardingSphere 配置指向 secondhand_trade 数据库
-- 3. 启动顺序: Nacos → MySQL → 各微服务 → 客户端
-- 4. 客户端连接 gateway:8088
-- ============================================================
